def merge_intervals(intervals):
    """Merge overlapping intervals in a list."""
    if not intervals:
        return []
    intervals.sort()
    merged = [intervals[0]]
    for i, interval in enumerate(intervals[1:], start=1):
        prev = merged[-1]
        if interval[0] <= prev[1]:
            # Overlapping: merge by extending the end
            merged[-1] = [prev[0], max(prev[1], interval[1])]
        else:
            # No overlap: add a new interval
            merged.append(interval)
    return merged

def flatten(lst):
    """Flatten a nested list into a single flat list."""
    out = []
    for x in lst:
        if isinstance(x, list):
            out.extend(flatten(x))
        else:
            out.append(x)
    return out
